// Solution
function routeValidation(routes) {
  for (let route of routes) {
    let path = route.path;
    let params = route.params;
    let isValid = true;
    try {
      let regex = new RegExp(path.replace(/:[^/]+/g, match => '\d+')); // Create a regular expression to match the route path
      for (let param in params) {
        if (!regex.test('/' + param)) {
          isValid = false;
        }
      }
    } catch (e) {
      isValid = false;
    }
    if (isValid) {
      result.push(true);
    } else {
      result.push(false);
    }
  }
  return result;
}
